html:
{% set inv = doc %}
{% set company = frappe.db.get_single_value("Global Defaults","default_company") or "Your Company" %}
{% set company_doc = frappe.get_doc("Company", company) if frappe.db.exists("Company", company) else None %}
{% set cur = inv.currency or "INR" %}
{% set cur_sym = frappe.db.get_value("Currency", cur, "symbol") or cur %}
{% macro fc(amount) %}{{ cur_sym }}{{ "{:,.2f}".format(amount|float) }}{% endmacro %}
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<link href="https://fonts.googleapis.com/css2?family=Inter:ital,wght@0,300;0,400;0,500;0,600;0,700;1,400&display=swap" rel="stylesheet">
<script src="https://cdnjs.cloudflare.com/ajax/libs/qrcodejs/1.0.0/qrcode.min.js"></script>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  :root {
    --ink-900: #0D1117;
    --ink-700: #1F2937;
    --ink-500: #6B7280;
    --ink-300: #D1D5DB;
    --ink-100: #F3F4F6;
    --ink-50:  #F9FAFB;
    --accent:  #1B55E2;       /* brand blue */
    --accent-light: #EEF3FD;
    --green:   #15803D;
    --green-bg:#DCFCE7;
    --amber:   #B45309;
    --amber-bg:#FEF3C7;
    --red:     #B91C1C;
    --red-bg:  #FEE2E2;
    --slate:   #4B5563;
    --slate-bg:#F1F5F9;
    --radius:  6px;
  }

  body {
    font-family: 'Inter', -apple-system, Arial, sans-serif;
    color: var(--ink-700);
    background: #fff;
    font-size: 12.5px;
    line-height: 1.5;
    -webkit-print-color-adjust: exact;
    print-color-adjust: exact;
  }

  .page {
    max-width: 794px;
    margin: 0 auto;
    padding: 0;
    background: #fff;
  }

  /* ═══════════════════════════════════════════════
     TOP ACCENT BAR
  ═══════════════════════════════════════════════ */
  .accent-bar {
    height: 5px;
    background: linear-gradient(90deg, var(--accent) 0%, #4F7EF5 100%);
  }

  /* ═══════════════════════════════════════════════
     HEADER
  ═══════════════════════════════════════════════ */
  .header-wrap {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    padding: 32px 44px 24px;
    gap: 24px;
  }

  .logo-col { display: flex; flex-direction: column; gap: 12px; }

  .logo-col img {
    max-height: 54px; max-width: 180px;
    object-fit: contain; object-position: left center;
  }
  .logo-placeholder {
    display: flex; align-items: center; justify-content: center;
    width: 140px; height: 50px;
    border: 1.5px dashed var(--ink-300); border-radius: var(--radius);
    font-size: 10.5px; color: var(--ink-500); letter-spacing: .3px;
  }

  .company-info { font-size: 11.5px; color: var(--ink-500); line-height: 1.65; }
  .company-name { font-size: 14.5px; font-weight: 700; color: var(--ink-900); margin-bottom: 3px; }

  /* Right: invoice identity */
  .inv-id-col { text-align: right; flex-shrink: 0; }
  .doc-type-chip {
    display: inline-block;
    background: var(--accent); color: #fff;
    font-size: 9px; font-weight: 700; letter-spacing: 2px; text-transform: uppercase;
    padding: 4px 12px; border-radius: 20px;
    margin-bottom: 8px;
  }
  .inv-number { font-size: 24px; font-weight: 700; color: var(--ink-900); letter-spacing: -.5px; }

  .meta-grid {
    margin-top: 10px;
    display: grid; grid-template-columns: auto auto; gap: 4px 20px;
    text-align: left;
  }
  .meta-grid .lbl { font-size: 10.5px; font-weight: 500; color: var(--ink-500); text-transform: uppercase; letter-spacing: .5px; }
  .meta-grid .val { font-size: 12.5px; font-weight: 600; color: var(--ink-900); }

  /* ═══════════════════════════════════════════════
     SECTION DIVIDER
  ═══════════════════════════════════════════════ */
  .section-divider { border: none; border-top: 1px solid var(--ink-300); margin: 0 44px; }

  /* ═══════════════════════════════════════════════
     PARTIES ROW
  ═══════════════════════════════════════════════ */
  .parties-wrap {
    display: flex; gap: 0;
    padding: 20px 44px;
  }
  .party-col { flex: 1; padding-right: 24px; }
  .party-col + .party-col { padding-left: 24px; padding-right: 0; border-left: 1px solid var(--ink-300); }

  .party-label {
    font-size: 9.5px; font-weight: 700; letter-spacing: 1.4px;
    text-transform: uppercase; color: var(--accent);
    margin-bottom: 5px;
  }
  .party-name { font-size: 14px; font-weight: 600; color: var(--ink-900); margin-bottom: 3px; }
  .party-detail { font-size: 11.5px; color: var(--ink-500); line-height: 1.65; }

  /* Status badge */
  .status-badge {
    display: inline-flex; align-items: center; gap: 5px;
    padding: 4px 11px; border-radius: 20px;
    font-size: 11px; font-weight: 600; letter-spacing: .3px;
  }
  .status-badge::before {
    content: ""; width: 6px; height: 6px; border-radius: 50%;
    background: currentColor; opacity: .7;
  }
  .badge-paid     { background: var(--green-bg); color: var(--green); }
  .badge-overdue  { background: var(--amber-bg); color: var(--amber); }
  .badge-draft    { background: var(--slate-bg); color: var(--slate); }
  .badge-partial  { background: var(--amber-bg); color: var(--amber); }
  .badge-submitted{ background: var(--accent-light); color: var(--accent); }

  /* ═══════════════════════════════════════════════
     ITEMS TABLE
  ═══════════════════════════════════════════════ */
  .table-wrap { padding: 0 44px; }

  .items-table { width: 100%; border-collapse: collapse; }

  .items-table thead tr {
    background: var(--ink-900);
  }
  .items-table thead th {
    padding: 10px 14px;
    font-size: 10px; font-weight: 600; letter-spacing: .7px;
    text-transform: uppercase; color: rgba(255,255,255,.75);
    text-align: left; white-space: nowrap;
  }
  .items-table thead th:first-child { border-radius: var(--radius) 0 0 0; }
  .items-table thead th:last-child  { border-radius: 0 var(--radius) 0 0; }
  .items-table thead th.r { text-align: right; }

  .items-table tbody tr { border-bottom: 1px solid var(--ink-100); }
  .items-table tbody tr:nth-child(even) { background: var(--ink-50); }
  .items-table tbody tr:last-child { border-bottom: none; }

  .items-table tbody td {
    padding: 11px 14px;
    font-size: 12.5px; color: var(--ink-700);
    vertical-align: top;
  }
  .items-table td.mono {
    font-variant-numeric: tabular-nums; text-align: right;
    font-size: 12.5px; color: var(--ink-900);
  }
  .row-num { color: var(--ink-300); font-size: 11px; }
  .item-name  { font-weight: 600; color: var(--ink-900); }
  .item-desc  { font-size: 11px; color: var(--ink-500); margin-top: 2px; }
  .item-hsn   { font-size: 10px; color: var(--ink-300); margin-top: 1px; }

  /* Table bottom border accent */
  .table-foot-bar {
    height: 3px;
    background: linear-gradient(90deg, var(--accent) 0%, #4F7EF5 100%);
    border-radius: 0 0 var(--radius) var(--radius);
    margin: 0; margin-bottom: 24px;
  }

  /* ═══════════════════════════════════════════════
     BOTTOM: NOTES + QR + TOTALS
  ═══════════════════════════════════════════════ */
  .bottom-wrap {
    display: flex;
    gap: 24px;
    padding: 0 44px 28px;
    align-items: flex-start;
  }

  /* Notes */
  .notes-col { flex: 1; display: flex; flex-direction: column; gap: 14px; }

  .notes-card {
    background: var(--ink-50); border: 1px solid var(--ink-100);
    border-radius: var(--radius); padding: 13px 16px;
  }
  .notes-card .card-title {
    font-size: 9.5px; font-weight: 700; letter-spacing: 1.2px;
    text-transform: uppercase; color: var(--ink-500); margin-bottom: 6px;
  }
  .notes-card p { font-size: 12px; color: var(--ink-700); line-height: 1.65; }

  /* QR */
  .qr-card {
    background: var(--ink-50); border: 1px solid var(--ink-100);
    border-radius: var(--radius); padding: 14px 18px;
    text-align: center;
  }
  .qr-card .card-title {
    font-size: 9.5px; font-weight: 700; letter-spacing: 1.2px;
    text-transform: uppercase; color: var(--ink-500); margin-bottom: 10px;
  }
  #qr-canvas { display: flex; justify-content: center; margin-bottom: 8px; }
  .qr-upi-id  { font-size: 10px; color: var(--ink-500); word-break: break-all; }
  .qr-amount  { font-size: 12px; font-weight: 600; color: var(--ink-900); margin-top: 4px; }

  /* Totals */
  .totals-col { min-width: 270px; }

  .totals-card {
    background: var(--ink-50); border: 1px solid var(--ink-100);
    border-radius: var(--radius); overflow: hidden;
  }
  .totals-table { width: 100%; border-collapse: collapse; }
  .totals-table tr + tr td { border-top: 1px solid var(--ink-100); }
  .totals-table td { padding: 9px 16px; font-size: 12.5px; }
  .totals-table td.t-lbl { color: var(--ink-500); }
  .totals-table td.t-val { text-align: right; font-variant-numeric: tabular-nums; font-weight: 500; color: var(--ink-900); }

  .grand-row { background: var(--ink-900) !important; }
  .grand-row td { border-top: none !important; color: #fff !important; font-size: 15px; font-weight: 700; padding: 12px 16px; }
  .grand-row td.t-lbl { color: rgba(255,255,255,.75) !important; }

  .payment-row td { color: var(--green) !important; }
  .balance-row { background: var(--red-bg) !important; }
  .balance-row td { color: var(--red) !important; font-weight: 700; border-top: none !important; }

  .total-words { font-size: 11px; color: var(--ink-500); font-style: italic; padding: 10px 16px; line-height: 1.5; }

  /* ═══════════════════════════════════════════════
     FOOTER
  ═══════════════════════════════════════════════ */
  .footer-wrap {
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
    padding: 18px 44px 28px;
    border-top: 1px solid var(--ink-300);
    margin: 0 0 0 0;
  }

  .thank-text { font-size: 14px; font-weight: 700; color: var(--ink-900); }
  .thank-sub  { font-size: 11px; color: var(--ink-500); margin-top: 2px; }

  .sig-block { text-align: center; }
  .sig-line {
    width: 150px; border-top: 1.5px solid var(--ink-300);
    margin: 0 auto 6px; padding-top: 6px;
  }
  .sig-label { font-size: 10.5px; color: var(--ink-500); letter-spacing: .3px; }

  /* ═══════════════════════════════════════════════
     STATUS RIBBON (corner)
  ═══════════════════════════════════════════════ */
  .ribbon-wrap { position: relative; overflow: hidden; }
  .ribbon {
    position: absolute; top: 22px; right: -30px;
    background: var(--amber); color: #fff;
    font-size: 9px; font-weight: 800; letter-spacing: 1px;
    padding: 5px 42px; transform: rotate(45deg);
    text-transform: uppercase; z-index: 10;
    box-shadow: 0 2px 8px rgba(0,0,0,.15);
  }
  .ribbon.paid    { background: var(--green); }
  .ribbon.overdue { background: var(--amber); }
  .ribbon.draft   { background: var(--slate); }

  /* ═══════════════════════════════════════════════
     PRINT
  ═══════════════════════════════════════════════ */
  @media print {
    .page { max-width: 100%; }
    body  { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  }

  /* ═══════════════════════════════════════════════
     E-INVOICE / IRN STRIP
  ═══════════════════════════════════════════════ */
  .einv-strip {
    display: flex; align-items: flex-start; justify-content: space-between;
    margin: 0 44px 0; padding: 12px 16px;
    background: #f0f4ff; border: 1px solid #c5d0fa; border-radius: 8px;
    gap: 16px;
  }
  .einv-left { flex: 1; min-width: 0; }
  .einv-title {
    font-size: 9.5px; font-weight: 700; letter-spacing: 1px; text-transform: uppercase;
    color: #3451b2; margin-bottom: 5px;
  }
  .einv-irn {
    font-family: 'Courier New', monospace; font-size: 9px; color: #1e3a8a;
    word-break: break-all; line-height: 1.5; letter-spacing: .3px;
    background: #e8eeff; padding: 5px 8px; border-radius: 4px; margin-bottom: 6px;
  }
  .einv-meta-row { font-size: 10px; color: var(--ink-700); display: flex; align-items: center; flex-wrap: wrap; gap: 4px; }
  .einv-meta-lbl { color: var(--ink-500); }
  .einv-meta-val { font-weight: 600; color: var(--ink-900); }
  .einv-qr { flex-shrink: 0; }
  .einv-qr canvas, .einv-qr img { display: block; }
</style>
</head>
<body>
<div class="page ribbon-wrap">

  <!-- Status corner ribbon -->
  {% if inv.status == "Paid" %}
  <div class="ribbon paid">Paid</div>
  {% elif inv.status == "Overdue" %}
  <div class="ribbon overdue">Overdue</div>
  {% elif inv.status == "Draft" %}
  <div class="ribbon draft">Draft</div>
  {% endif %}

  <!-- ── TOP ACCENT BAR ── -->
  <div class="accent-bar"></div>

  <!-- ── HEADER ── -->
  <div class="header-wrap">
    <div class="logo-col">
      {% set logo_url = company_doc.company_logo if company_doc and company_doc.company_logo else None %}
      {% if logo_url %}
        <img src="{{ logo_url }}" alt="{{ company }} logo" />
      {% else %}
        <div class="logo-placeholder">Your Logo Here</div>
      {% endif %}
      <div class="company-info">
        <div class="company-name">{{ company }}</div>
        {% if company_doc %}
          {{ company_doc.address or "" }}<br>
          {% if company_doc.city %}{{ company_doc.city }}, {% endif %}{{ company_doc.country or "India" }}<br>
          {% if company_doc.tax_id %}<strong style="color:var(--ink-700)">GSTIN:</strong> {{ company_doc.tax_id }}{% endif %}
        {% else %}
          Tamil Nadu, India
        {% endif %}
      </div>
    </div>

    <div class="inv-id-col">
      <div class="doc-type-chip">Tax Invoice</div>
      <div class="inv-number">{{ inv.name }}</div>
      <div class="meta-grid">
        <span class="lbl">Invoice Date</span>
        <span class="val">{{ frappe.format(inv.posting_date, "Date") }}</span>
        <span class="lbl">Due Date</span>
        <span class="val">{{ frappe.format(inv.due_date, "Date") }}</span>
        <span class="lbl">Terms</span>
        <span class="val">{{ inv.payment_terms_template or "Due on Receipt" }}</span>
        {% if inv.po_no %}
        <span class="lbl">P.O. #</span>
        <span class="val">{{ inv.po_no }}</span>
        {% endif %}
      </div>
    </div>
  </div>

  <hr class="section-divider">

  <!-- ── PARTIES ── -->
  <div class="parties-wrap">
    <div class="party-col">
      <div class="party-label">Bill To</div>
      <div class="party-name">{{ inv.customer_name }}</div>
      <div class="party-detail">
        {{ inv.address_display | replace("<br>", "\n") | striptags | replace("\n", "<br>") if inv.address_display else inv.customer }}
      </div>
    </div>
    <div class="party-col" style="flex:0 0 200px; text-align:center;">
      <div class="party-label" style="text-align:center">Status</div>
      {% set smap = {"Paid":"badge-paid","Overdue":"badge-overdue","Draft":"badge-draft","Partly Paid":"badge-partial","Submitted":"badge-submitted"} %}
      <div style="margin-bottom:10px">
        <span class="status-badge {{ smap.get(inv.status,'badge-draft') }}">{{ inv.status }}</span>
      </div>
      <div class="party-label" style="text-align:center; margin-top:6px">Currency</div>
      <div style="font-size:13px; font-weight:600; color:var(--ink-900)">{{ inv.currency or "INR" }}</div>
    </div>
  </div>

  <hr class="section-divider" style="margin-bottom:16px">

  <!-- ── ITEMS TABLE ── -->
  <div class="table-wrap">
    <table class="items-table">
      <thead>
        <tr>
          <th style="width:32px">#</th>
          <th>Item &amp; Description</th>
          <th class="r" style="width:70px">Qty</th>
          <th class="r" style="width:110px">Rate</th>
          <th class="r" style="width:120px">Amount</th>
        </tr>
      </thead>
      <tbody>
        {% for item in inv.items %}
        <tr>
          <td><span class="row-num">{{ loop.index }}</span></td>
          <td>
            <div class="item-name">{{ item.item_name }}</div>
            {% if item.description and item.description != item.item_name %}
              <div class="item-desc">{{ item.description }}</div>
            {% endif %}
            {% if item.gst_hsn_code %}<div class="item-hsn">HSN: {{ item.gst_hsn_code }}</div>{% endif %}
          </td>
          <td class="mono">{{ item.qty }}&nbsp;<span style="font-size:10.5px;color:var(--ink-500)">{{ item.uom or "pcs" }}</span></td>
          <td class="mono">{{ fc(item.rate) }}</td>
          <td class="mono" style="font-weight:600">{{ fc(item.amount) }}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
    <div class="table-foot-bar"></div>
  </div>

  <!-- ── BOTTOM SECTION ── -->
  <div class="bottom-wrap">

    <!-- Notes + QR (left column) -->
    <div class="notes-col">
      {% if inv.terms %}
      <div class="notes-card">
        <div class="card-title">Notes &amp; Terms</div>
        <p>{{ inv.terms }}</p>
      </div>
      {% endif %}

      {% if cur == "INR" %}
      <div class="qr-card">
        <div class="card-title">Pay via UPI</div>
        <div id="qr-canvas"></div>
        <div class="qr-upi-id" id="upi-id-display">
          {{ company_doc.custom_upi_id if company_doc and company_doc.get("custom_upi_id") else "yourupi@bank" }}
        </div>
        <div class="qr-amount">
          Balance: {{ fc(inv.outstanding_amount or inv.grand_total) }}
        </div>
      </div>
      {% endif %}
    </div>

    <!-- Totals (right column) -->
    <div class="totals-col">
      <div class="totals-card">
        <table class="totals-table">
          <tr>
            <td class="t-lbl">Sub Total</td>
            <td class="t-val">{{ fc(inv.net_total) }}</td>
          </tr>
          {% for tax in inv.taxes %}
          <tr>
            <td class="t-lbl">{{ tax.description }} ({{ tax.rate }}%)</td>
            <td class="t-val">{{ fc(tax.tax_amount) }}</td>
          </tr>
          {% endfor %}
          <tr class="grand-row">
            <td class="t-lbl">Total</td>
            <td class="t-val">{{ fc(inv.grand_total) }}</td>
          </tr>
          {% if inv.total_advance > 0 %}
          <tr class="payment-row">
            <td class="t-lbl">Payment Made</td>
            <td class="t-val">(–) {{ fc(inv.total_advance) }}</td>
          </tr>
          {% endif %}
          {% if inv.outstanding_amount > 0 %}
          <tr class="balance-row">
            <td class="t-lbl" style="font-weight:600">Balance Due</td>
            <td class="t-val">{{ fc(inv.outstanding_amount) }}</td>
          </tr>
          {% endif %}
        </table>
        {% if inv.in_words %}
        <div class="total-words">{{ inv.in_words }}</div>
        {% endif %}
      </div>
    </div>

  </div>

  <!-- ── E-INVOICE / IRN STRIP ── -->
  {% if inv.irn and inv.einvoice_status != 'Cancelled' %}
  <div class="einv-strip">
    <div class="einv-left">
      <div class="einv-title">e-Invoice (IRN)</div>
      <div class="einv-irn">{{ inv.irn }}</div>
      <div class="einv-meta-row">
        <span class="einv-meta-lbl">Ack No.</span>
        <span class="einv-meta-val">{{ inv.ack_no or '—' }}</span>
        <span class="einv-meta-lbl" style="margin-left:20px">Ack Date</span>
        <span class="einv-meta-val">{{ frappe.format(inv.ack_date, "Date") if inv.ack_date else '—' }}</span>
      </div>
    </div>
    <div class="einv-qr">
      <div id="einv-qr-canvas"></div>
    </div>
  </div>
  {% endif %}

  <!-- ── FOOTER ── -->
  <div class="footer-wrap">
    <div>
      <div class="thank-text">Thank you for your business.</div>
      <div class="thank-sub">We appreciate your prompt payment.</div>
    </div>
    <div class="sig-block">
      <div class="sig-line"></div>
      <div class="sig-label">Authorized Signatory</div>
    </div>
  </div>

</div>

{% if cur == "INR" %}
<script>
(function() {
  try {
    var upiId = document.getElementById("upi-id-display").textContent.trim();
    var amountEl = document.querySelector(".qr-amount");
    var amountText = amountEl ? amountEl.textContent.replace(/[^0-9.]/g,"").trim() : "0";
    var companyName = {{ company | tojson }};
    var invName = {{ inv.name | tojson }};
    var upiString = "upi://pay?pa=" + encodeURIComponent(upiId)
      + "&pn=" + encodeURIComponent(companyName)
      + "&am=" + encodeURIComponent(amountText)
      + "&cu=INR"
      + "&tn=" + encodeURIComponent("Payment for " + invName);
    var container = document.getElementById("qr-canvas");
    new QRCode(container, {
      text: upiString,
      width: 100, height: 100,
      colorDark: "#0D1117",
      colorLight: "#F9FAFB",
      correctLevel: QRCode.CorrectLevel.M
    });
  } catch(e) {
    var container = document.getElementById("qr-canvas");
    if (container) container.innerHTML = '<div style="width:100px;height:100px;display:flex;align-items:center;justify-content:center;font-size:10px;color:#9AA0AB;border:1px dashed #ccc;border-radius:4px">QR unavailable</div>';
  }
})();
</script>
{% endif %}

{% if inv.irn and inv.einvoice_status != 'Cancelled' %}
<script>
(function() {
  try {
    var irn = {{ inv.irn | tojson }};
    var container = document.getElementById("einv-qr-canvas");
    if (container && irn) {
      new QRCode(container, {
        text: irn,
        width: 80, height: 80,
        colorDark: "#1e3a8a",
        colorLight: "#e8eeff",
        correctLevel: QRCode.CorrectLevel.M
      });
    }
  } catch(e) {
    var c = document.getElementById("einv-qr-canvas");
    if (c) c.innerHTML = '<div style="width:80px;height:80px;display:flex;align-items:center;justify-content:center;font-size:9px;color:#9AA0AB;border:1px dashed #c5d0fa;border-radius:4px">QR unavailable</div>';
  }
})();
</script>
